1	package validation
2	
3	import (
4		"fmt"
5		"net"
6		"net/url"
7		"strings"
8	
9		"github.com/go-git/go-git/v6/plumbing"
10	)
11	
12	const (
13		ProtocolAuto = "auto"
14		ProtocolV1   = "v1"
15		ProtocolV2   = "v2"
16	)
17	
18	// RefMapping is a user-specified source:target mapping.
19	type RefMapping struct {
20		Source string
21		Target string
22	}
23	
24	// NormalizedMapping is a validated mapping normalized to fully-qualified refs.
25	type NormalizedMapping struct {
26		SourceRef plumbing.ReferenceName
27		TargetRef plumbing.ReferenceName
28	}
29	
30	// ValidateEndpoints rejects configurations where the source and target URLs
31	// point at the same repository. Empty URLs are ignored so the caller can
32	// surface a more specific "missing URL" error.
33	func ValidateEndpoints(sourceURL, targetURL string) error {
34		src := normalizeEndpointURL(sourceURL)
35		dst := normalizeEndpointURL(targetURL)
36		if src == "" || dst == "" {
37			return nil
38		}
39		if src == dst {
40			return fmt.Errorf("source and target must not be the same repository: %s", src)
41		}
42		return nil
43	}
44	
45	func normalizeEndpointURL(raw string) string {
46		trimmed := strings.TrimRight(strings.TrimSpace(raw), "/")
47		if trimmed == "" {
48			return ""
49		}
50	
51		parsed, err := url.Parse(trimmed)
52		if err != nil || parsed.Host == "" {
53			return trimmed
54		}
55		if parsed.Scheme != "http" && parsed.Scheme != "https" {
56			return trimmed
57		}
58	
59		scheme := strings.ToLower(parsed.Scheme)
60		host := strings.ToLower(parsed.Hostname())
61		port := parsed.Port()
62		if port != "" && !isDefaultPort(scheme, port) {
63			host = net.JoinHostPort(host, port)
64		}
65	
66		path := strings.TrimRight(parsed.EscapedPath(), "/")
67		if path == "" {
68			path = "/"
69		}
70	
71		normalized := scheme + "://" + host + path
72		if parsed.RawQuery != "" {
73			normalized += "?" + parsed.RawQuery
74		}
75		if parsed.Fragment != "" {
76			normalized += "#" + parsed.Fragment
77		}
78		return normalized
79	}
80	
81	func isDefaultPort(scheme, port string) bool {
82		return (scheme == "http" && port == "80") || (scheme == "https" && port == "443")
83	}
84	
85	// NormalizeProtocolMode validates the configured protocol mode and applies the
86	// default auto mode when the user did not specify one.
87	func NormalizeProtocolMode(mode string) (string, error) {
88		if mode == "" {
89			return ProtocolAuto, nil
90		}
91		switch mode {
92		case ProtocolAuto, ProtocolV1, ProtocolV2:
93			return mode, nil
94		default:
95			return "", fmt.Errorf("unsupported protocol mode %q", mode)
96		}
97	}
98	
99	// ParseMapping parses a CLI --map value into a ref mapping.
100	func ParseMapping(raw string) (RefMapping, error) {
101		parts := strings.SplitN(raw, ":", 2)
102		if len(parts) != 2 {
103			return RefMapping{}, fmt.Errorf("invalid --map %q, expected src:dst", raw)
104		}
105		source := strings.TrimSpace(parts[0])
106		target := strings.TrimSpace(parts[1])
107		if source == "" || target == "" {
108			return RefMapping{}, fmt.Errorf("invalid --map %q, expected src:dst", raw)
109		}
110		return RefMapping{Source: source, Target: target}, nil
111	}
112	
113	// ParseHaveRef normalizes a have-ref CLI value. Short names are treated as
114	// branch names for compatibility with other CLI ref selectors.
115	func ParseHaveRef(raw string) plumbing.ReferenceName {
116		raw = strings.TrimSpace(raw)
117		if strings.HasPrefix(raw, "refs/") {
118			return plumbing.ReferenceName(raw)
119		}
120		return plumbing.NewBranchReferenceName(raw)
121	}
122	
123	// NormalizeMapping validates and normalizes a single ref mapping.
124	func NormalizeMapping(m RefMapping) (NormalizedMapping, error) {
125		src := strings.TrimSpace(m.Source)
126		dst := strings.TrimSpace(m.Target)
127		if src == "" || dst == "" {
128			return NormalizedMapping{}, fmt.Errorf("invalid mapping %q:%q: source and target must be non-empty", m.Source, m.Target)
129		}
130	
131		srcFQ := strings.HasPrefix(src, "refs/")
132		dstFQ := strings.HasPrefix(dst, "refs/")
133	
134		if srcFQ && dstFQ {
135			sourceRef := plumbing.ReferenceName(src)
136			targetRef := plumbing.ReferenceName(dst)
137			srcKind := refKind(sourceRef)
138			dstKind := refKind(targetRef)
139			if srcKind == "" {
140				return NormalizedMapping{}, fmt.Errorf("unsupported source ref kind: %s", src)
141			}
142			if dstKind == "" {
143				return NormalizedMapping{}, fmt.Errorf("unsupported target ref kind: %s", dst)
144			}
145			if srcKind != dstKind {
146				return NormalizedMapping{}, fmt.Errorf("cross-kind mapping not allowed: %s (%s) -> %s (%s)", src, srcKind, dst, dstKind)
147			}
148			return NormalizedMapping{SourceRef: sourceRef, TargetRef: targetRef}, nil
149		}
150	
151		if !srcFQ && !dstFQ {
152			return NormalizedMapping{
153				SourceRef: plumbing.NewBranchReferenceName(src),
154				TargetRef: plumbing.NewBranchReferenceName(dst),
155			}, nil
156		}
157	
158		return NormalizedMapping{}, fmt.Errorf("ambiguous mapping: cannot mix fully-qualified and short ref names: %q -> %q", src, dst)
159	}
160	
161	// ValidateMappings normalizes all mappings and rejects duplicate target refs.
162	func ValidateMappings(mappings []RefMapping) ([]NormalizedMapping, error) {
163		if len(mappings) == 0 {
164			return nil, nil
165		}
166	
167		normalized := make([]NormalizedMapping, 0, len(mappings))
168		targetSeen := make(map[plumbing.ReferenceName]string, len(mappings))
169	
170		for _, m := range mappings {
171			nm, err := NormalizeMapping(m)
172			if err != nil {
173				return nil, err
174			}
175			if prev, exists := targetSeen[nm.TargetRef]; exists {
176				return nil, fmt.Errorf("duplicate target ref %s: mapped from both %q and %q", nm.TargetRef, prev, m.Source)
177			}
178			targetSeen[nm.TargetRef] = m.Source
179			normalized = append(normalized, nm)
180		}
181		return normalized, nil
182	}
183	
184	func refKind(name plumbing.ReferenceName) string {
185		switch {
186		case name.IsBranch():
187			return "branch"
188		case name.IsTag():
189			return "tag"
190		default:
191			return ""
192		}
193	}
