76	func TestValidateEndpoints(t *testing.T) {
77		t.Parallel()
78	
79		tests := []struct {
80			name    string
81			source  string
82			target  string
83			wantErr bool
84		}{
85			{name: "different URLs", source: "https://src.example/r.git", target: "https://dst.example/r.git"},
86			{name: "same URL", source: "https://example.com/r.git", target: "https://example.com/r.git", wantErr: true},
