88			{name: "same URL with userinfo", source: "https://user@example.com/r.git", target: "https://example.com/r.git", wantErr: true},
89			{name: "same URL with default https port", source: "https://example.com:443/r.git", target: "https://example.com/r.git", wantErr: true},
90			{name: "same URL with default http port", source: "http://example.com:80/r.git", target: "http://example.com/r.git", wantErr: true},
91			{name: "same URL with mixed host case", source: "https://EXAMPLE.com/r.git", target: "https://example.com/r.git", wantErr: true},
92			{name: "different non-default port", source: "https://example.com:8443/r.git", target: "https://example.com/r.git"},
93			{name: "empty source defers to other checks", source: "", target: "https://example.com/r.git"},
94			{name: "empty target defers to other checks", source: "https://example.com/r.git", target: ""},
95			{name: "both empty defers to other checks", source: "", target: ""},
96			{name: "differ only by trailing slash", source: "https://example.com/r.git", target: "https://example.com/r.git/", wantErr: true},
97			{name: "differ only by repeated trailing slashes", source: "https://example.com/r.git//", target: "https://example.com/r.git/", wantErr: true},
98		}
99	
100		for _, tt := range tests {
101			t.Run(tt.name, func(t *testing.T) {
102				t.Parallel()
103	
104				err := ValidateEndpoints(tt.source, tt.target)
105				if tt.wantErr {
106					if err == nil {
107						t.Fatalf("ValidateEndpoints(%q, %q) = nil, want error", tt.source, tt.target)
108					}
109					return
110				}
111				if err != nil {
112					t.Fatalf("ValidateEndpoints(%q, %q) = %v, want nil", tt.source, tt.target, err)
113				}
