23	// BuildDesiredRefs constructs the set of desired refs and managed targets from
24	// source refs and user configuration. All mapping validation happens here,
25	// before any network activity (issue #2, #3).
26	func BuildDesiredRefs(
27		sourceRefs map[plumbing.ReferenceName]plumbing.Hash,
28		cfg PlanConfig,
29	) (map[plumbing.ReferenceName]DesiredRef, map[plumbing.ReferenceName]ManagedTarget, error) {
30		desired := make(map[plumbing.ReferenceName]DesiredRef)
31		managed := make(map[plumbing.ReferenceName]ManagedTarget)
32	
33		addManaged := func(sourceRef, targetRef plumbing.ReferenceName, kind RefKind, hash plumbing.Hash) error {
34			if hash.IsZero() {
35				return fmt.Errorf("source ref %s not found", sourceRef)
36			}
37			// Reject duplicate target refs from different sources (issue #2, #3).
38			if existing, ok := desired[targetRef]; ok && existing.SourceRef != sourceRef {
39				return fmt.Errorf("duplicate target ref %s: mapped from both %s and %s", targetRef, existing.SourceRef, sourceRef)
40			}
41			short := targetRef.Short()
42			desired[targetRef] = DesiredRef{
43				Kind:       kind,
44				Label:      short,
45				SourceRef:  sourceRef,
46				TargetRef:  targetRef,
47				SourceHash: hash,
48			}
49			managed[targetRef] = ManagedTarget{Kind: kind, Label: short}
50			return nil
51		}
52	
53		if len(cfg.Mappings) > 0 {
54			// Validate all mappings up front (issue #2, #3)
55			normalized, err := validation.ValidateMappings(cfg.Mappings)
56			if err != nil {
57				return nil, nil, fmt.Errorf("validate ref mappings: %w", err)
58			}
59			for _, nm := range normalized {
60				kind := RefKindFromName(nm.TargetRef)
61				if err := addManaged(nm.SourceRef, nm.TargetRef, kind, sourceRefs[nm.SourceRef]); err != nil {
62					return nil, nil, err
63				}
64			}
65		} else {
66			branches := BranchMapFromRefHashMap(sourceRefs)
67			selected := SelectBranches(branches, cfg.Branches)
68			for branch, hash := range selected {
69				refName := plumbing.NewBranchReferenceName(branch)
70				if err := addManaged(refName, refName, RefKindBranch, hash); err != nil {
71					return nil, nil, err
72				}
73			}
74		}
75	
76		if cfg.IncludeTags {
77			for refName, hash := range sourceRefs {
78				if !refName.IsTag() {
79					continue
80				}
81				if err := addManaged(refName, refName, RefKindTag, hash); err != nil {
82					return nil, nil, err
83				}
84			}
85		}
86	
87		return desired, managed, nil
88	}
