224	func copyManagedTargets(input map[plumbing.ReferenceName]ManagedTarget) map[plumbing.ReferenceName]ManagedTarget {
225		out := make(map[plumbing.ReferenceName]ManagedTarget, len(input))
226		for k, v := range input {
227			out[k] = v
228		}
229		return out
230	}
