232	// BuildBootstrapPlans creates plans for an empty-target bootstrap.
233	func BuildBootstrapPlans(
234		desired map[plumbing.ReferenceName]DesiredRef,
235		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
236	) ([]BranchPlan, error) {
237		targetNames := make([]plumbing.ReferenceName, 0, len(desired))
238		for _, want := range desired {
239			targetNames = append(targetNames, want.TargetRef)
240		}
241		sort.Slice(targetNames, func(i, j int) bool { return targetNames[i] < targetNames[j] })
242	
243		plans := make([]BranchPlan, 0, len(targetNames))
244		for _, targetRef := range targetNames {
245			targetHash := targetRefs[targetRef]
246			if !targetHash.IsZero() {
247				return nil, fmt.Errorf("target ref %s already exists; use sync for non-bootstrap runs", targetRef)
248			}
249			want := desired[targetRef]
250			plans = append(plans, BranchPlan{
251				Branch:     want.Label,
252				SourceRef:  want.SourceRef,
253				TargetRef:  want.TargetRef,
254				SourceHash: want.SourceHash,
255				TargetHash: plumbing.ZeroHash,
256				Kind:       want.Kind,
257				Action:     ActionCreate,
258				Reason:     fmt.Sprintf("create %s at %s", want.TargetRef, ShortHash(want.SourceHash)),
259			})
260		}
261		return plans, nil
262	}
