319	// PlanReplicationRef determines the overwrite-oriented action for a single ref.
320	func PlanReplicationRef(want DesiredRef, targetHash plumbing.Hash, existsOnTarget bool) BranchPlan {
321		plan := BranchPlan{
322			Branch:     want.Label,
323			SourceRef:  want.SourceRef,
324			TargetRef:  want.TargetRef,
325			SourceHash: want.SourceHash,
326			TargetHash: targetHash,
327			Kind:       want.Kind,
328		}
329	
330		if want.SourceHash == targetHash {
331			plan.Action = ActionSkip
332			plan.Reason = ShortHash(want.SourceHash) + " already current"
333			return plan
334		}
335	
336		if !existsOnTarget || targetHash.IsZero() {
337			plan.Action = ActionCreate
338			plan.Reason = ShortHash(want.SourceHash) + " -> <new>"
339			return plan
340		}
341	
342		plan.Action = ActionUpdate
343		switch want.Kind {
344		case RefKindTag:
345			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (replicate tag overwrite)"
346		case RefKindBranch:
347			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (replicate overwrite)"
348		default:
349			plan.Reason = ShortHash(targetHash) + " -> " + ShortHash(want.SourceHash) + " (replicate overwrite)"
350		}
351		return plan
352	}
