370	func instrumentHTTPClient(base *http.Client, skipTLS bool, label string, stats *statsCollector) *http.Client {
371		if base == nil {
372			base = &http.Client{Transport: gitproto.NewHTTPTransport(skipTLS)}
373		}
374		clone := *base
375		baseRT := clone.Transport
376		if baseRT == nil {
377			baseRT = gitproto.NewHTTPTransport(skipTLS)
378		}
379		clone.Transport = &countingRoundTripper{base: baseRT, label: label, stats: stats}
380		return &clone
381	}
